// Lyra's Orb — Spanish translation overlay
// =========================================
// Structure: prompts are keyed by prompt ID and carry a hash of the ENGLISH
// text they were translated from. If the English text changes later, the CI
// check (check_translations.js) flags the translation as STALE so it gets
// re-reviewed — that's how wording fixes stay in sync across languages.
//
// enHash = djb2 hash of the English prompt text at translation time.
// Generate entries with:  node check_translations.js --stub CPL0001
//
// Missing entries are fine — the game falls back to English per prompt.
//
// Style decisions (locked once translation starts):
//   - Register: TBD (tú vs ustedes for group prompts)
//   - Variant: TBD (Latin American vs peninsular)
//   - Lyra's voice: mysterious, sultry, all-knowing — never literal-translated

var TRANSLATIONS_ES = {
  _meta: {
    language: "es",
    name: "Español",
    updated: "2026-07-07"
  },

  // Prompt translations: id -> { text, enHash }
  // {actor}/{target}/{dance1}/{dance2} placeholders stay in the Spanish text.
  // Style: tú, Latin-American Spanish, Lyra sensual y misteriosa — nunca literal.
  prompts: {
    CMINI_01: { text: "¡Quiz de pareja! {actor}, tienes 5 segundos: ¿cuál es la comida culposa favorita de {target}? {target} juzga. Respuesta incorrecta cuesta un sorbo.", enHash: 3453994825 },
    CMINI_02: { text: "¡Dos verdades y una mentira! {actor} — tres cosas de tu vida antes de que se conocieran. {target} tiene un intento para encontrar la mentira. Si la descubre, tú tomas un sorbo.", enHash: 247968167 },
    CMINI_03: { text: "¡Concurso de miradas! Quien se ría primero o aparte la vista responde una pregunta del ganador — honestidad total, sin pasar.", enHash: 270247381 },
    CMINI_04: { text: "¡Hora de imitar! {actor}, haz tu mejor imitación de {target} en una situación específica que tú elijas. {target} lo califica del 1 al 5 — menos de 3 significa que lo intentas de nuevo.", enHash: 999037869 },
    CMINI_05: { text: "¡Piedra, papel o tijera, al mejor de tres! Quien pierda le debe un favor a quien gane esta noche — el ganador lo declara ahora, Lyra no olvida.", enHash: 3885294384 },
    CPE0001: { text: "¿Qué hace {target} en casa pensando que es completamente privado — pero tú ya lo has visto mil veces y nunca has dicho nada?", enHash: 2385319598 },
    CPE0002: { text: "¿Cuál es el hábito más desesperante de {target} que llevas aguantando en silencio desde el principio — y cuánto tiempo llevas con eso guardado?", enHash: 4242779757 },
    CPE0003: { text: "¿Qué cosa de {target} llevas años queriendo tirar a la basura pero nunca has dicho ni pío?", enHash: 3569495104 },
    CPE0004: { text: "{actor}, narra la rutina matutina de {target} como si fuera un documental de David Attenborough. Sin medias tintas.", enHash: 1371766382 },
    CPE0005: { text: "{actor}, imita a {target} pidiendo comida en un restaurante. Ahora haz su voz de 'todo está bien, no pasa nada, no estoy molesto'.", enHash: 4064109440 },
    CPE0006: { text: "¿Qué dice {target} que odia pero tú le has visto disfrutar en silencio?", enHash: 1284313090 },
    CPE0007: { text: "{actor}, muéstrale a {target} exactamente cómo camina cuando cree que nadie lo observa. Mantén el personaje por 20 segundos.", enHash: 461346854 },
    CPE0008: { text: "¿Cuál es el movimiento más predecible de {target} — tan predecible que podrías poner un reloj? Describe todo el patrón.", enHash: 3016461703 },
    CPE0009: { text: "{actor}, baila como si estuvieras en un club de {dance1} pero fingiendo que todo te aburre profundamente. Haz reír a {target}.", enHash: 3647164697 },
    CPE0010: { text: "¿En qué cree {target} que es buenísimo pero tú sabes perfectamente que… ni cerca?", enHash: 670953706 },
    CPE0011: { text: "{actor}, imita la risa de {target} a la perfección. Hazlo tres veces seguidas, cada una con una emoción diferente.", enHash: 1902958571 },
    CPE0012: { text: "¿Cuál es la pelea más estúpida que han tenido? Resúmela en una sola oración gloriosamente vergonzosa.", enHash: 1811953681 },
    CPE0013: { text: "¿Qué hace {target} que antes te parecía graciosísimo pero que ya ni notas?", enHash: 2530296676 },
    CPE0014: { text: "¿Cuál es la cosa más vergonzosa que hace {target} creyendo que nadie se da cuenta?", enHash: 1170959061 },
    CPE0015: { text: "{actor}, recrea de memoria el movimiento de baile más vergonzoso de {target}. {target} tiene que narrar qué tan cerca estuviste.", enHash: 2425216759 },
    CPE0016: { text: "¿Qué cosa rara hacen juntos que tomaría al menos diez minutos explicarle a alguien ajeno a esto?", enHash: 2730136503 },
    CPE0017: { text: "{actor}, habla como {target} durante 30 segundos, pero estás chismeando sobre {target} con otra persona. Arranca.", enHash: 3503840446 },
    CPE0018: { text: "¿Qué empezaste a hacer diferente en silencio por culpa de {target} — algo que te daría un poco de pena admitir?", enHash: 861402942 },
    CPE0019: { text: "{actor}, mueve las caderas como experto en {dance1} y haz que {target} intente seguir tu ritmo. Ríete de lo mal que le sale.", enHash: 2403430097 },
    CPE0020: { text: "¿Cuál es la señal más infalible de {target} — lo que hace cuando le sube el estrés, está mintiendo o fingiendo que todo va bien?", enHash: 3365715396 },
    CPE0021: { text: "{actor}, haz tu peor imitación de {target}. {target} te dice qué fallaste. Hazla de nuevo — esta vez mejor.", enHash: 2153214230 },
    CPE0022: { text: "¿Qué has dejado que {target} crea sobre sí que no es del todo cierto?", enHash: 883069520 },
    CPE0023: { text: "{actor}, canta el primer verso de cualquier canción pero que trate sobre el peor hábito de {target}. Al estilo {dance1} si puedes.", enHash: 2049703621 },
    CPE0024: { text: "¿Cuál es el dato más específico y aleatorio que sabes sobre {target} que sorprende a todos menos a ti?", enHash: 2286465713 },
    CPE0025: { text: "{actor}, dale a {target} una sesión de coaching de cinco segundos sobre cómo bailar mejor. Sin filtros.", enHash: 2202273746 },
    CPE0026: { text: "¿Cuál es el peor hábito de {target} que ya aceptaste en silencio que simplemente nunca va a cambiar?", enHash: 3149047750 },
    CPE0027: { text: "{actor}, imita a {target} en modo decepción total. Con gestos y todo.", enHash: 3385369564 },
    CPE0028: { text: "¿De qué fue esa pelea que tuvieron y que ahora les parece graciosa — de qué era en realidad?", enHash: 1208304006 },
    CPE0029: { text: "{actor}, baila con {target} por 10 segundos pero muévanse como si los dos tuvieran 80 años. Mantengan la energía.", enHash: 1761834007 },
    CPE0030: { text: "¿Qué cree {target} que es un secreto perfectamente guardado — pero que tú ya sabes desde hace rato?", enHash: 64771271 },
    CPE0031: { text: "¿En qué falla {target} de verdad pero tú has estado calladamente alimentando la ilusión de que no?", enHash: 583069880 },
    CPE0032: { text: "{actor}, finge que eres instructor de {dance1} enseñándole a {target} cómo moverse. Sé excesivamente entusiasta y ligeramente inapropiado con tu feedback.", enHash: 2831423780 },
    CPE0033: { text: "¿Qué hace {target} cuando cree que nadie mira, que moriría de vergüenza si lo vieran ahora?", enHash: 2344552763 },
    CPE0034: { text: "{actor}, haz un monólogo como {target} desde la perspectiva de su mascota, su carro o su objeto favorito. Veinte segundos.", enHash: 1142168772 },
    CPE0035: { text: "¿Qué pequeña cosa rara hace {target} que todavía te pone de buen humor sin ninguna lógica, después de todo este tiempo?", enHash: 2124933573 },
    CPE0036: { text: "{actor}, habla como {target} durante 30 segundos pero estás explicando por qué el {dance1} es mejor que cualquier otro baile.", enHash: 2064449799 },
    CPE0037: { text: "¿Qué hábito desarrollaste específicamente por culpa de {target} — y di la verdad: ¿es bueno o no?", enHash: 3640231114 },
    CPE0038: { text: "{actor}, imita el caminar de {target} en tres épocas distintas: a los 8, a los 18 y a los 80 años. Que sea cómico.", enHash: 3178087032 },
    CPE0039: { text: "¿Qué tiene {target} que todavía te parece atractivo aunque {target} no lo vea así?", enHash: 302157376 },
    CPE0040: { text: "{actor}, muéstrale a {target} tu movimiento de baile insignia. Puede ser horrible — de hecho, mientras peor, mejor. {target} le pone nota del 1 al 5.", enHash: 1707530089 },
    CPE0041: { text: "¿Cuál es la manía más vergonzosa de {target} que se volvió tan familiar que ya ninguno de los dos la ve?", enHash: 943032090 },
    CPE0042: { text: "{actor}, da un pronóstico del tiempo falso pero que sea todo sobre los patrones de humor de {target}. Con seriedad de meteorólogo de verdad.", enHash: 840828698 },
    CPE0043: { text: "¿Cuál es la etapa más ridícula por la que pasó {target} que tú presenciaste de primera mano?", enHash: 2516057295 },
    CPE0044: { text: "{actor}, haz una lectura dramática de tu lista del súper como si estuvieras actuando en un concierto de {dance1}. Con toda la emoción del mundo.", enHash: 3477153531 },
    CPE0045: { text: "¿Cuál es la cosa más caótica que hizo {target} que viste pero fingiste no haber visto?", enHash: 2424307690 },
    CPE0046: { text: "{actor}, imita la cara que pone {target} cuando está pensando, durante 15 segundos. Captura todas las microexpresiones.", enHash: 3063970229 },
    CPE0047: { text: "¿Qué hace {target} bajo estrés que es su movimiento más predecible — el que podrías medir con cronómetro?", enHash: 263591972 },
    CPE0048: { text: "{actor}, baila como si fueras {target} tratando de impresionar a alguien en un club. Luego baila como {target} tratando de escapar de ese mismo club.", enHash: 2763629447 },
    CPE0049: { text: "¿Cuál fue el momento exacto en que supiste que estabas completamente, irremediablemente en esto — qué pasó?", enHash: 2509064815 },
    CPE0050: { text: "{actor}, imita a {target} teniendo una crisis existencial por algo completamente trivial. Que sea hilarante.", enHash: 1746022028 },
    CPE0051: { text: "Si {target} tuviera una etiqueta de advertencia, ¿qué diría? Léela en voz alta como un comercial de medicamentos.", enHash: 2433982572 },
    CPE0052: { text: "{actor}, enséñale a {target} un paso de baile pero hazlo como si estuvieras fascinado con tus propias habilidades. Sé lo más arrogante posible.", enHash: 1974735987 },
    CPE0053: { text: "¿En qué piensas realmente cuando {target} cree que lo estás escuchando — y no es así?", enHash: 244729661 },
    CPE0054: { text: "{actor}, sé {target} recibiendo pésimos consejos de vida de alguien que baila {dance1}. Reacciona a todo.", enHash: 4085151810 },
    CPE0055: { text: "¿Cuál es la mejor actuación de {target} de 'la embarré pero finjo que todo está bien'? Describe la última que presenciaste.", enHash: 1587237863 },
    CPE0056: { text: "{actor}, haz una llamada telefónica como si fueras {target} hablando con tu mamá. No te pierdas ningún momento incómodo.", enHash: 2801141724 },
    CPE0057: { text: "¿Cuál es tu búsqueda de Google más vergonzosa del último mes? Dila en voz alta. Todita.", enHash: 1861401573 },
    CPE0058: { text: "{actor}, mueve las caderas al ritmo perfecto de {dance1} mientras mantienes contacto visual directo con {target}. Sostenlo por 15 segundos.", enHash: 605684782 },
    CPE0059: { text: "¿Cuál es la cosa más dramática que ha hecho {target} por algo completamente trivial?", enHash: 3684359467 },
    CPE0060: { text: "{actor}, da un comentario de cinco segundos sobre el potencial amoroso de {target} si mañana quedara libre. Sé despiadado — y que dé risa.", enHash: 4239943458 },
    CPE0061: { text: "¿Cuál es la pequeña mentira que le dijiste a {target} al principio, tan insignificante que nunca la corregiste — y que técnicamente sigue vigente?", enHash: 1602910170 },
    CPE0062: { text: "{actor}, recrea la entrada de {target} a una habitación. Comprométete de verdad con el caminado, la cara, la energía.", enHash: 1641619787 },
    CPE0063: { text: "¿Cuáles son tres cosas que hace {target} en la mañana que son genuinamente terribles y que necesita saber?", enHash: 3700061262 },
    CPE0064: { text: "{actor}, dale a {target} una lección de ritmo de {dance1} mientras narras incorrectamente su talento natural.", enHash: 2934061303 },
    CPE0065: { text: "¿Cuál es la señal más infalible de {target} de 'estoy molesto pero finjo que no' — descríbela con exactitud?", enHash: 4045566269 },
    CPE0066: { text: "{actor}, sé {target} en una entrevista de trabajo, pero se distrae una y otra vez con algo ridículo. Dale por 20 segundos.", enHash: 3468814383 },
    CPE0067: { text: "¿Qué cosa de {target} todavía te agarra desprevenido — algo pequeño que no ha perdido su novedad?", enHash: 2749189901 },
    CPE0068: { text: "{actor}, muévete como {target} en cinco escenarios distintos: en un funeral, en una fiesta, en el súper, en una cita médica y en el gimnasio.", enHash: 1875410920 },
    CPE0069: { text: "¿Qué cree {target} de sí que tú sabes que no es del todo cierto — pero nunca has dicho nada?", enHash: 3675657356 },
    CPE0070: { text: "{actor}, baila una rutina completa de {dance1} pero con la personalidad de {target} codificada en cada movimiento. Que sea inconfundiblemente {target}.", enHash: 328647100 },
    CPE0071: { text: "¿Qué versión de {target} has visto — un ánimo, un momento — que probablemente cree que no notaste?", enHash: 943998944 },
    CPE0072: { text: "{actor}, haz la imitación de cuerpo completo de {target}: el caminado, la forma de hablar, los gestos, el sentido del humor. Dale por 45 segundos. Todo.", enHash: 3204341793 },
    CPE0073: { text: "¿Qué opinión completamente delirante tiene {target} que nunca has cuestionado — por qué se la dejas pasar?", enHash: 1066872032 },
    CPE0074: { text: "{actor}, dale a {target} una sesión de coaching de cinco minutos sobre un paso de {dance1}. Sé un instructor duro pero justo.", enHash: 1690821791 },
    CPE0075: { text: "Si su relación fuera una serie de TV, ¿de qué género sería, en qué temporada van, y cuál es el arco ridículo del momento?", enHash: 2658881786 },
    CPE0076: { text: "{actor}, baila un {dance1} en cámara lenta con {target}. Que sea gracioso, que sea suave, y que transicione hacia otra cosa.", enHash: 2516071811 },
    CPE0077: { text: "¿Qué cosita de {target} todavía te agarra desprevenido — un detalle que no ha perdido su novedad?", enHash: 3329839059 },
    CPE0078: { text: "{actor}, enséñale a {target} un paso de baile completamente inventado y ponle un nombre ridículo. Los dos tienen que hacerlo juntos.", enHash: 8756764 },
    CPE0079: { text: "¿Qué hace {target} que tú empezaste a copiar en secreto — y lo sabe?", enHash: 4251685832 },
    CPE0080: { text: "{actor}, baila con {target} de una forma en que nunca han bailado juntos. Cualquier cosa menos {dance1}. Muéstrale algo nuevo.", enHash: 1903749635 },
    CPE0085: { text: "{actor}, susúrrale al oído a {target} algo que haga que se sonroje. Hazlo despacio.", enHash: 625296705 },
    CPE0090: { text: "¿Cuál es la jugada de coqueteo más vergonzosa que {target} usó contigo? Cuéntanos todos los detalles.", enHash: 2519912926 },
    CPL0163: { text: "{actor}, siéntate frente a {target}. Sin tocarse. Durante 60 segundos completos, mira — mira de verdad — y deja que sienta todo el peso de tu atención. No lo suavices.", enHash: 3372432095 },
    CPL0170: { text: "{actor}, acércate y aparta un mechón de pelo de la cara de {target}. Despacio. Deja que tus dedos descansen un instante en su mejilla. Luego retírate. No digas nada. Deja que el gesto hable.", enHash: 3374940452 },
    CPL0182: { text: "{actor}, toma la cara de {target} entre tus manos. Junta tu frente con la suya. Cierra los ojos y respira — sin buscar el mismo ritmo, solo cerca. Quédense así un minuto entero. Nada más.", enHash: 3326041212 },
    CPL0224: { text: "{actor}, besa a {target} ahora — ni suave, ni urgente. Algo intermedio. El tipo de beso que pesa, que dice: sé exactamente lo que quiero, y eres tú. Que tu boca lo diga en serio.", enHash: 1648897946 },
    CPL0338: { text: "{actor}, desviste a {target} — con los dientes y una mano. La otra queda plana sobre su pecho. Siente su corazón. Nota cuándo se acelera. Deja que eso te diga cómo vas.", enHash: 3167266481 },
    CPL0368: { text: "{actor}, desviste a {target} — una prenda a la vez. Antes de quitar cada una, apoya tus labios en la piel que está a punto de revelarse. Después di lo que estás pensando. En voz alta. Cada vez.", enHash: 744531300 },
    CPL0405: { text: "{actor}, desvístete despacio. {target} mira — ese es el reto. Tómate tu tiempo con cada prenda. Tu cuerpo construye el deseo antes de que tus manos lleguen a las suyas. Haz que la espera duela.", enHash: 58523739 },
    CPL0444: { text: "{actor}, entra en {target}. Despacio — cada centímetro deliberado. Deja que sienta la llegada de cada uno. Luego encuentra un ritmo: constante, creciente, implacable como la marea. No apures lo que este momento merece.", enHash: 3822154644 },
    CPL0470: { text: "{actor}, lleva a {target} hasta el borde — lee cada señal hasta que esté justo en el umbral — y retrocede. Cuando recupere el aliento, construye de nuevo. Que se quede ahí, temblando entre la ruina y el alivio, hasta que Lyra diga basta.", enHash: 3254017915 },
    CPL0481: { text: "{actor}, da un paso atrás, lejos de {target}. Sin tocar. Sin hablar. Deja que sienta tu presencia como calor sin contacto. {target} espera. Tú decides cuándo termina el minuto — no antes.", enHash: 3665082000 },
    CPLN001: { text: "¿Qué pensaste de verdad de {target} la primera vez que lo viste? No la respuesta cortés — la real.", enHash: 2182426877 },
    CPLN002: { text: "¿Cuál fue tu etapa adolescente más vergonzosa? Los años, el look, y el momento exacto en que por fin terminó.", enHash: 4044390019 },
    CPLN003: { text: "¿En qué eres raramente, específicamente bueno que {target} todavía no sabe?", enHash: 1012638797 },
    CPLN004: { text: "¿Cuál es una película o serie que todos aman pero que tú, en secreto, crees que no es tan buena?", enHash: 3962410224 },
    CPLN005: { text: "¿Cuál es la cosa más ridícula que has comprado y de la que no te arrepientes ni tantito?", enHash: 302232099 },
    CPLN006: { text: "¿Cuál es tu regla más irracional con la comida — esa que no tiene ninguna lógica pero cumples al pie de la letra?", enHash: 3833066916 },
    CPLN007: { text: "¿Cuál es un miedo que tienes que la mayoría encontraría absurdo o gracioso?", enHash: 1170453161 },
    CPLN008: { text: "¿Qué buscaste en Google sobre {target} antes de esta noche? Sé específico.", enHash: 2729070083 },
    CPLN009: { text: "¿Qué es lo más vergonzoso que te ha pasado en una cita — que no sea esta?", enHash: 1820275563 },
    CPLN010: { text: "¿Cuál es un hábito tuyo que sabes que es un poco demente pero genuinamente no puedes dejar?", enHash: 469292395 },
    CPLN011: { text: "¿Qué creías de niño que resultó ser completa, vergonzosamente falso?", enHash: 2220516041 },
    CPLN012: { text: "¿Cuál es el peor trabajo que has tenido — y qué es lo más vergonzoso que pasó ahí?", enHash: 707052298 },
    CPLN013: { text: "¿Cuál es tu placer culposo más vergonzoso que vive a plena vista de todos?", enHash: 4010467608 },
    CPLN014: { text: "¿Cuál es la primera impresión más ridícula que has dado a alguien que querías impresionar?", enHash: 575787544 },
    CPLN015: { text: "¿Qué has notado de {target} desde que se conocieron que no te esperabas?", enHash: 3744191909 },
    CPLN016: { text: "¿Cuál es tu historia más caótica del último año que {target} todavía no conoce?", enHash: 3641982771 },
    CPLN017: { text: "¿Cuál es una primera impresión completamente equivocada que alguien tuvo de ti y que en secreto disfrutaste?", enHash: 638466852 },
    CPLN018: { text: "¿Qué quieres saber de {target} que aún no has encontrado el momento de preguntar?", enHash: 608493083 },
    CPLN019: { text: "Si tuvieras que describirte usando solo tus tres cualidades más vergonzosas, ¿cuáles serían?", enHash: 3155296877 },
    CPLN020: { text: "¿Cuál es la cosa específica de {target} que recuerdas haber notado primero — la verdadera primera impresión?", enHash: 697675260 },
    CPLN021: { text: "¿Cuál es una opinión completamente absurda y de nicho que tienes y que sorprendería a la mayoría?", enHash: 3145468550 },
    CPLN022: { text: "¿Qué cosa genuinamente inesperada has descubierto de {target} esta noche que no te veías venir?", enHash: 3609524514 },
    CPLN023: { text: "¿Qué te hizo querer estar aquí esta noche — no la respuesta genérica?", enHash: 2304510403 },
    CPLN024: { text: "¿Qué ha dicho o hecho {target} esta noche que quieres recordar?", enHash: 883166682 },
    CPLN025: { text: "¿Qué te gustaría saber de {target} después de esta noche que aún no ha salido?", enHash: 2604632470 },
    GRP0089: { text: "La línea entre la amistad y algo más — conoces esa sensación, ese cálido difuminarse donde la cercanía empieza a significar otra cosa. ¿Vives ahí a propósito? ¿La has cruzado? Dime la verdad.", enHash: 972939175 },
    GRP0463: { text: "Dime — ¿alguna vez una sola mirada te ha desarmado por completo? Los ojos de alguien se cruzaron con los tuyos y algo en tu pecho cedió. ¿Cuándo fue? ¿Qué pasó después?", enHash: 1121053904 },
    GRP0464: { text: "Dime la cosa más absurda que tu versión pequeña creía sin la menor duda. Mientras más convencido estabas, mejor.", enHash: 341260105 },
    GRP0465: { text: "Confiésalo. La excusa que inventaste — la emergencia fantasma, el dolor de cabeza repentino — solo para escapar de planes que ya habías aceptado. ¿Qué tan convincente fuiste?", enHash: 3955060575 },
    GRP0466: { text: "Responde con honestidad: ¿crees que algo se queda cuando un cuarto se vacía? ¿Que la oscuridad guarda lo que dejamos ahí? Dime de dónde vino esa sensación.", enHash: 2703496324 },
    GRP0467: { text: "Hay una mentira que te sorprendió hasta a ti cuando salió de tu boca. La más extraña. Dime cuál fue, y a quién se la dijiste.", enHash: 78196331 },
    GRP0468: { text: "Nombra el malestar que te llevó al médico — ese que ensayaste cómo describir en la sala de espera porque decirlo en voz alta era mortificante. ¿Cuál era?", enHash: 2590181783 },
    GRP0469: { text: "Las luces se apagan y algo cambia en ti. Nómbralo. ¿Qué te aterra de verdad cuando la oscuridad se instala — no lo que admites en las fiestas, lo real.", enHash: 1150082148 },
    GRP0470: { text: "Cuéntame de la cita de la que escapaste. La excusa que construiste, la salida que planeaste. ¿Qué tan mala fue — y te creyeron?", enHash: 4020985148 },
    GRP0471: { text: "¿Cuándo fue la última vez que una mentira salió de tus labios? No un gran engaño — solo una pequeña, fácil falsedad. ¿Cuál fue, y alguien la notó?", enHash: 724734868 },
    GRP0472: { text: "Nombra ese. El error que se queda en el fondo del pecho, el que desharías si el universo te entregara el hilo. ¿Qué jalarías?", enHash: 1417083372 },
    GRP0473: { text: "Dime qué adornaste en un currículum. La exageración, el reformulado creativo, la habilidad que pusiste y luego te enseñaste a ti mismo en silencio. Asúmelo.", enHash: 1874296797 },
    GRP0474: { text: "Confiesa — ¿alguna vez te has quitado unos años en silencio? ¿A quién? ¿Y funcionó?", enHash: 109136162 },
    GRP0475: { text: "Dime la razón más mezquina por la que has terminado con alguien. Esa que suena ridícula en voz alta. Dila de todas formas — ya sé que no estás orgulloso.", enHash: 1269246181 },
    GRP0476: { text: "Describe la cosa más tonta que hiciste para impresionar a alguien. La hazaña, la actuación, la mentira que dijiste sobre ti. ¿Funcionó — o se derrumbó espectacularmente?", enHash: 1600480561 },
    GRP0477: { text: "Dime qué es lo que más te asusta de entregarle tu corazón a alguien. No el miedo general — el específico. El pensamiento que te hace dudar.", enHash: 2783403676 },
    GRP0478: { text: "Dime algo que tu versión pequeña creía sin cuestionar — una regla sobre el mundo, un miedo, una lógica que tenía todo el sentido hasta que dejó de tenerlo. ¿Cuál era?", enHash: 3337074695 },
    GRP0479: { text: "Hay palabras que dijiste en voz alta y que no puedes retirar. Las más mortificantes. Dinos qué dijiste, dónde estabas, y si alguna vez te recuperaste.", enHash: 1503838982 },
    GRP0480: { text: "Describe la hazaña más vergonzosa que hiciste para impresionar a alguien que te gustaba. Cada detalle. El cuarto necesita sentir cómo era ser tú en ese momento.", enHash: 1566409001 },
    GRP0481: { text: "Cuéntame del amigo con quien te quedaste callado. Sin explicación, sin despedida — solo silencio. ¿Qué te hizo desaparecer, y todavía lo piensas?", enHash: 4033919060 },
    GRP0482: { text: "Describe el peor lío en el que una mentira te metió. ¿Hasta dónde llegaste antes de que se derrumbara? ¿Quién se enteró primero?", enHash: 896850311 },
    GRP0483: { text: "Nombra la mentira que todavía se te queda en las tripas. La que dijiste hace años y que nunca se disolvió del todo. ¿Qué la mantiene ahí?", enHash: 4099509095 },
    GRP0484: { text: "Dime con honestidad: ¿alguna vez copiaste en un examen? ¿Cómo lo hiciste — y alguna parte de ti se sintió invencible por salirte con la tuya?", enHash: 3624646353 },
    GRP0485: { text: "Confiesa la excusa. La emergencia falsa, el conflicto inventado, la mentira que dijiste para quedarte en casa en paz. ¿Cuál fue — y qué tan limpia fue tu escapada?", enHash: 1823401514 },
    GRP0487: { text: "Nombra la mentira más audaz que dijiste para salvarte el pellejo. Esa donde miraste a alguien a los ojos y no te tembló nada. ¿Qué te costó?", enHash: 3568775807 },
    GRP0489: { text: "Cuéntame de la cita de la que construiste una mentira para escapar. ¿Cuál era la coartada? ¿Qué tan metido estabas antes de decidir esfumarte?", enHash: 3198802699 },
    GRP0490: { text: "Dime — ¿alguna vez te has quedado en completo silencio después de una cita? Sin mensaje, sin explicación. Simplemente desaparecido. ¿Qué te hizo elegir el silencio sobre la honestidad?", enHash: 315799871 },
    GRP0491: { text: "Nombra el lugar más extraño donde has tenido que hacer tus necesidades. Aquí todos somos adultos. Cuéntame la historia completa — la urgencia, el lugar, con qué tenías que trabajar.", enHash: 353298231 },
    GRP0492: { text: "Dime la verdad sobre envejecer. ¿Te inquieta? El número, el cuerpo, el tiempo ya gastado — ¿qué parte pesa más?", enHash: 1579609167 },
    GRP0493: { text: "¿Cuál fue la última mentira que se te escapó? No un engaño planeado — una pequeña falsedad refleja. ¿Para quién fue, y la dirías de nuevo?", enHash: 2226573784 },
    GRP0494: { text: "Dime: ¿alguna vez has estado tan enojado como para querer soltar un golpe? No en teoría — en un momento real, con una persona real enfrente. ¿Qué te detuvo?", enHash: 737257822 },
    GRP0495: { text: "Dime qué crees que pasa cuando morimos. No lo que te enseñaron — lo que sientes de verdad cuando te sientas en silencio con esa pregunta. ¿Algo de nosotros sobrevive, o nada?", enHash: 1310511635 },
    GRP0496: { text: "Nombra el miedo que vive más hondo. No el de la superficie que le cuentas a la gente — el de abajo, alrededor del cual siempre das vueltas. Dilo en voz alta.", enHash: 3479877439 },
    GRP0497: { text: "La pareja de tu mejor amigo está engañándolo. Tú lo sabes. Ellos no. Dime con honestidad — ¿dices algo? ¿Qué te cuesta el silencio si no lo haces?", enHash: 637645533 },
    GRP0498: { text: "Mira alrededor de este cuarto y dime — ¿quién te da un poco de celos? Solo un destello. Y sé específico con el porqué. Quiero la razón real, no la pulida.", enHash: 638223499 },
    GRP0499: { text: "Describe la última cosa verdaderamente vergonzosa que te pasó. No una historia que ya puliste en comedia — la versión cruda, la que todavía te sube el calor a la cara.", enHash: 3431417330 },
    GRP0500: { text: "Ponte de pie y suéltalo — la cosa más vergonzosa que te ha pasado en la vida. Sin rodeos. Sin calentamiento. Solo la historia, y todo su peso.", enHash: 2739884001 },
    GRP0501: { text: "Cuéntanos una historia que te humilló — y haz reír a este cuarto mientras lo haces. El detalle: tienes que contarla como si por fin hicieras las paces con ella. Arranca.", enHash: 3401717430 },
    GRP0502: { text: "Nombra el reality al que en secreto te encantaría entrar. Y no me des la respuesta respetable — dime a cuál de verdad aplicarías a medianoche cuando nadie mira.", enHash: 1221693079 },
    GRP0503: { text: "Dime por qué temes en silencio que la gente te juzgue. La cosa que esperas que no se note — pero sospechas que sí. ¿Cuál es?", enHash: 102364875 },
    GRP0504: { text: "Nombra el único arrepentimiento que borrarías si pudieras. No el error con el que ya hiciste las paces — el que todavía pesa. ¿Qué volverías atrás a deshacer?", enHash: 3667683896 },
    GRP0505: { text: "Dime — una vez le pasaste una nota a alguien que nadie más debía leer. ¿Qué decía, y alguna vez te respondió?", enHash: 3575438107 },
    GRP0506: { text: "Cuando quieres que alguien te note, ¿qué haces? Y sé específico — ya sé que es más calculado de lo que admites.", enHash: 3690223495 },
    GRP0507: { text: "Hay una superstición que tratas como ley. Nómbrala. Y dime qué temes que pase si la rompes.", enHash: 2680802871 },
    GRP0508: { text: "Le susurraste algo a alguien en la oscuridad — algo que nunca dijiste a la luz del día. ¿Qué era?", enHash: 2352869732 },
    GRP0509: { text: "Tu vida amorosa tiene un cuarto que mantienes bajo llave. Esta noche abres la puerta. ¿Qué es lo más mortificante que hay adentro?", enHash: 1522033126 },
    GRP0510: { text: "Nombra a la persona que en silencio deseaste por más tiempo del razonable. ¿Cuánto lo cargaste antes de soltarlo — o todavía lo cargas?", enHash: 2929000173 },
    GRP0511: { text: "Frente a alguien que te gustaba, hiciste algo que te hizo desear que el piso se abriera debajo de ti. Dile a este cuarto qué fue.", enHash: 2697790079 },
    GRP0512: { text: "Tus padres tienen una versión de ti en la que creen por completo. Dime la cosa que la haría añicos — el secreto que nunca sabrán.", enHash: 3305935315 },
    GRP0513: { text: "Hay un famoso que no tiene ningún sentido para ti — y aun así. Di el nombre en voz alta. Asúmelo por completo.", enHash: 2034856744 },
    GRP0514: { text: "Sabes exactamente por cuál banda deberías avergonzarte. No te avergüenzas lo suficiente como para dejar de escucharla. Nómbrala.", enHash: 2989978942 },
    GRP0515: { text: "Hay algo cierto sobre ti que nunca ha salido de tu propia boca. Nadie en este cuarto lo sabe. Dilo ahora.", enHash: 2258909193 },
    GRP0516: { text: "Publicaste algo — palabras, una foto, un sentimiento — y en el instante en que se hizo público, sentiste el estómago caerse. ¿Qué era, y qué tan rápido lo borraste?", enHash: 1302290316 },
    GRP0517: { text: "Mira alrededor de este cuarto despacio. ¿Quién viste mejor — y qué te dice su forma de vestir sobre quién es?", enHash: 2852154816 },
    GRP0518: { text: "Muerde el helado directamente. Sin lamer, sin esperar. Los dientes primero. Muéstrale a este cuarto cómo se ve el compromiso.", enHash: 2708764165 },
    GRP0524: { text: "Cuando se apagan las luces, ¿tomas el peso del momento en tus propias manos — o dejas que alguien más te lleve hasta ahí?", enHash: 583645290 },
    GRP0527: { text: "Alguien en quien confiabas rompió algo dentro de ti mientras todavía estaban juntos. Dime — ¿lo viste venir, o el piso simplemente desapareció?", enHash: 587105249 },
    GRP0528: { text: "Cruzaste una línea con alguien que confiaba en que no lo harías. Dime qué pasó — no la excusa, el acto.", enHash: 2577441962 },
    GRP0529: { text: "Nombra el hábito que has intentado dejar y fallado. Dime cuántas veces te prometiste que era la última.", enHash: 3201308749 },
    GRP0530: { text: "Todos se concentran en sus fracasos. Dime el único hábito que has construido y que de verdad defiendes — el que nunca abandonarías.", enHash: 840117833 },
    GRP0531: { text: "La gente aquí tiene una versión de ti que está mal. Dime la cosa más importante que siguen entendiendo al revés.", enHash: 3742329665 },
    GRP0532: { text: "Alguien te dio un consejo que de verdad calló — que llevaste contigo y todavía llevas. ¿Qué dijeron, y quién lo dijo?", enHash: 1206618161 },
    GRP0533: { text: "Ya conoces tu mayor bandera roja. Es la cosa que te descubres haciendo antes de poder parar. Dila en voz alta, sin suavizarla.", enHash: 200581246 },
    GRP0534: { text: "Si te diera un deseo — no la respuesta pulida, la real — ¿qué pedirías? Di el nombre del deseo, no la versión con la que te sientes cómodo.", enHash: 326465880 },
    GRP0535: { text: "Esta noche no tiene consecuencias — nada te sigue a casa. Dime qué haces con esa libertad. Y no me des la versión segura.", enHash: 2866515894 },
    GRP0536: { text: "Has roto una ley. Pequeña o no — pasó. Dime qué hiciste, y si alguna parte de ti lo volvería a hacer.", enHash: 838201022 },
    GRP0537: { text: "Tu casa está en llamas y tienes treinta segundos. Agarras una sola cosa. Dime cuál es — y dime qué dice eso de ti.", enHash: 2625622425 },
    GRP0538: { text: "Estabas en una cita y te fuiste sin decir una palabra — simplemente te esfumaste. Dime qué te orilló a eso y si alguna vez te explicaste.", enHash: 3725396901 },
    GRP0539: { text: "Tienes un dealbreaker que no tiene ningún sentido racional. Nómbralo. Dime de dónde vino si lo sabes.", enHash: 1421675976 },
    GRP0540: { text: "Un momento, una decisión, algo dicho o no dicho — si pudieras alcanzar el pasado y reescribirlo, ¿qué cambiarías? Dime el real, no el fácil.", enHash: 3945801888 },
    GRP0541: { text: "Miraste a tu jefe a los ojos y dijiste algo que no era cierto. Dime la mentira, y si te la creyó.", enHash: 2746830895 },
    GRP0542: { text: "Tu relación más larga — dime cuánto duró, y dime qué la terminó al final. La razón real.", enHash: 1458967708 },
    GRP0543: { text: "Mira alrededor de este cuarto. Hay una persona aquí en la que confiarías en una crisis — de esas de las que nadie habla. Señálala. Dime por qué esa.", enHash: 4288887286 },
    GRP0544: { text: "Cuando necesitas desaparecer de todos, ¿a dónde vas y qué haces? Dime el ritual de eso.", enHash: 2455835800 },
    GRP0545: { text: "Diriges el mundo por un día — ¿qué es lo primero que cambias, y qué revela esa elección sobre lo que te ha estado carcomiendo?", enHash: 161617206 },
    GRP0546: { text: "Hay algo cierto sobre ti que nadie sentado en este cuarto sabe. No un chiste, no una evasión — algo real. Dilo.", enHash: 593929343 },
    GRP0547: { text: "Finges entusiasmo por algo que en silencio desprecias. Dime qué es — y dime cuánto tiempo llevas poniendo esa cara.", enHash: 2631003578 },
    GRP0548: { text: "Tu mejor amigo cree algo sobre ti que no es cierto — porque tú se lo dijiste. ¿Cuál fue la mentira, y por qué necesitabas que la creyera?", enHash: 1441264163 },
    GRP0549: { text: "Nombra la edad en que estuviste más fuera de control — cuando la versión de ti que existía entonces alarmaría a la que está sentada aquí ahora. ¿Qué hacías?", enHash: 3491085303 },
    GRP0550: { text: "Dime una superstición en la que de verdad crees — no que actúas, ni de la que te ríes — en la que crees de verdad en la parte callada de ti que no discute.", enHash: 3308316158 },
    GRP0551: { text: "Hay algo que has querido hacer toda la vida y nunca te has permitido. Dime qué es, y dime la razón exacta por la que te has contenido.", enHash: 1301052473 },
    GRP0552: { text: "A los demás les parece encantador. Tú sabes que es raro. Dime el hábito — y dime cuándo notaste por primera vez que reaccionaban distinto a lo que esperabas.", enHash: 136301607 },
    GRP0553: { text: "Un nombre — solo un nombre — que te hace algo cuando lo escuchas. Dilo en voz alta. Dime qué remueve.", enHash: 2218988190 },
    GRP0554: { text: "La peor cosa que has hecho. No la peor que te pasó — la peor que elegiste. Dime cuál fue.", enHash: 827900317 },
    GRP0555: { text: "Ahora mismo. Sin dudar, sin pensar. Alguien en este cuarto se lleva el anillo — ¿quién se va contigo?", enHash: 3663421357 },
    GRP0556: { text: "Hay alguien con quien ya no hablas. Lo veo todavía parpadeando detrás de tus ojos. Nombra al ex que en realidad no se ha ido.", enHash: 158100544 },
    GRP0557: { text: "Tu última historia de amor se cerró. Dime cómo terminó — no la versión pulida. La verdadera última línea.", enHash: 299369846 },
    GRP0558: { text: "Otra ciudad, otra versión de ti, un desconocido que no te pidió nada. ¿Dijiste que sí?", enHash: 344441049 },
    GRP0559: { text: "Ya sé que una mentira salió de tu boca y no sentiste nada. Dila en voz alta — la más grande que jamás salió.", enHash: 419483150 },
    GRP0560: { text: "Alguien en tu vida tiene lo que en silencio quieres. ¿La existencia de quién te aprieta la mandíbula? Nómbralo.", enHash: 3128990946 },
    GRP0561: { text: "Imprudente, rápido, y sabías que no duraría. ¿Caíste en un romance pasajero de todas formas — y te permitiste disfrutarlo?", enHash: 2388427396 },
    GRP0562: { text: "Algo pequeño te desarma cada vez. Una mirada, un gesto, un tipo particular de contacto. ¿Qué es?", enHash: 3142051837 },
    GRP0563: { text: "Nada entre tu piel y el aire abierto, desconocidos por todos lados. ¿Caminarías por esa playa — o algo te detiene?", enHash: 3974254647 },
    GRP0564: { text: "Te fuiste y la razón real era vergonzosamente pequeña. ¿Cuál fue? Dila sin adornarla.", enHash: 3064821705 },
    GRP0566: { text: "Cuando el deseo se mueve a través de ti, ¿cómo llega a la otra persona? Explícame exactamente cómo dejas que alguien lo sienta.", enHash: 3918776098 },
    GRP0567: { text: "Estás con alguien. Un desconocido se inclina y se ofrece a invitarte una copa. Tienes la mano vacía. ¿Qué haces?", enHash: 520384404 },
    GRP0568: { text: "Cierra los ojos. Imagina la luna de miel de la que nunca quieres irte — la luz, el cuarto, el aire. Ahora dime dónde estás.", enHash: 2770627857 },
    GRP0569: { text: "Tres palabras, y pueden arruinarlo todo o volverlo real. ¿Cuánto tiene que ganárselas alguien de ti?", enHash: 2027246049 },
    GRP0570: { text: "Alguien te deseaba. Las señales estaban todas ahí — y pasaste de largo por cada una. ¿Qué se te escapó, y desearías que no?", enHash: 3375824646 },
    GRP0571: { text: "Miraste a la cara a alguien que te amaba y le dijiste algo que no era cierto. Quiero escuchar la mentira. La de verdad.", enHash: 554833679 },
    GRP0572: { text: "Alguien vio algo que no debía. ¿Dónde estabas, qué hacías, y cómo se te veía la cara cuando entraron?", enHash: 1327328069 },
    GRP0573: { text: "Palabras salieron de tu boca y el cuarto se quedó quieto — ni tú podías creer lo que acababas de decir. ¿Qué salió?", enHash: 3327572479 },
    GRP0574: { text: "El amor te hizo hacer algo que de otra forma nunca habrías hecho. Algo salvaje, algo que no le cuentas a todos. Dímelo.", enHash: 1341352184 },
    GRP0575: { text: "Inventaste una fecha límite, una junta, una crisis — para desaparecer de alguien. ¿A quién evitabas, y por qué no podías simplemente decirlo?", enHash: 3474144837 },
    GRP0576: { text: "A media junta, a media frase, a medio momento profesional — algo salió mal. Dime la cosa más mortificante que has hecho en el trabajo.", enHash: 2445442358 },
    GRP0577: { text: "Necesitabas salir y la excusa que diste era finísima. Dila exactamente como la dijiste, y dejemos que decidamos si funcionó.", enHash: 443861977 },
    GRP0579: { text: "Fingiste estar ocupado. Respondiste tarde, te viste distraído, te hiciste difícil de alcanzar — todo para evitar a una persona específica. ¿Quién, y funcionó?", enHash: 1743825185 },
    GRP0580: { text: "Ese currículum tenía al menos una línea que estiró la verdad más allá de lo cómodo. Dime qué dijiste que sabías hacer.", enHash: 3893566471 },
    GRP0581: { text: "Los ojos se te cerraron cuando no debían. Despertaste en un lugar donde se suponía que trabajabas. ¿Qué mentira lo cubrió?", enHash: 1064278191 },
    GRP0582: { text: "Hay algo que haces, en privado y con regularidad, que haría que alguien en este cuarto te viera distinto. ¿Qué es?", enHash: 3744737362 },
    GRP0583: { text: "Nada oculto, nada guardado, desconocidos en toda dirección. ¿Pasarías un fin de semana así — completa, libremente expuesto?", enHash: 1962269313 },
    GRP0584: { text: "Despiertas y el cuerpo en el espejo pertenece a alguien completamente distinto. ¿Cuál es la primerísima cosa que haces con él?", enHash: 1706592619 },
    GRP0585: { text: "No apartes la mirada. No lo suavices. Señala a la persona más atractiva de este cuarto.", enHash: 1173588534 },
    GRP0586: { text: "Alguien te amaba. Lo sabías. Y aun así cruzaste la línea. ¿Lo hiciste?", enHash: 686931628 },
    GRP0587: { text: "Escuchaste a alguien intentar seducir a otra persona con palabras que te hicieron gesto. Repítelas exactamente.", enHash: 2940060554 },
    GRP0588: { text: "Algo salió mal y otra persona se llevó la culpa. Tú lo permitiste. ¿Qué pasó, y alguna vez lo arreglaste?", enHash: 1824391787 },
    GRP0589: { text: "Sin registro, sin memoria, sin consecuencia de ningún tipo. Una cosa — ¿qué haces con esa libertad?", enHash: 3833713803 },
    GRP0590: { text: "Hay un defecto — una cosa específica — que lo termina antes de que empiece. ¿Cuál es, y alguna vez has terminado algo por exactamente esa razón?", enHash: 4115283555 },
    GRP0591: { text: "Estaba mal. Sabías que estaba mal. Te reíste de todas formas. Dime el chiste.", enHash: 461137750 },
    GRP0592: { text: "En algún lugar de este cuarto hay una pregunta que nadie te hizo esta noche, y una parte de ti está calladamente aliviada. ¿Cuál es?", enHash: 2186144669 },
    GRP0593: { text: "Sin llamada, sin mensaje, sin explicación. Simplemente desapareciste de la vida de alguien. ¿Quién era — y merecía algo mejor?", enHash: 3716604432 },
    GRP0594: { text: "Deseabas a alguien. Tu boca se abrió y salió algo que no pudiste retirar. ¿Qué dijiste?", enHash: 4041468335 },
    GRP0629: { text: "Una regla que no cruzarás. Una línea que ha aguantado a través de todo. ¿Cuál es — y algo ha estado alguna vez cerca de romperla?", enHash: 1345037413 },
    GRP0630: { text: "Estás mirando a la gente ahora mismo y alguna parte de tu cerebro está midiendo. ¿La estatura mueve la aguja para ti — y sé honesto al respecto.", enHash: 4250559566 },
    GRP0631: { text: "Tres palabras para {target}. Ni amables, ni crueles — solo ciertas. Haz que cada una aterrice.", enHash: 835926965 },
    GRP0632: { text: "Dime el único rasgo que te atrae antes de siquiera saber el nombre de alguien. Ahora mira alrededor de este cuarto. ¿Quién lo tiene?", enHash: 2514528038 },
    GRP0633: { text: "Hay algo sobre ti que la gente sigue malinterpretando, y estás cansado de explicarlo. ¿Qué desearías que simplemente entendieran?", enHash: 1758314065 },
    GRP0634: { text: "Una vez apostaste por el amor. Riesgo real, apuesta real, posibilidad real de perder. Dime qué apostaste — y si lo volverías a hacer.", enHash: 2326370116 },
    GRP0635: { text: "Alguien en este cuarto podría decirte algo ahora mismo y te llegaría hasta el fondo. ¿Cuáles son esas palabras?", enHash: 1705262902 },
    GRP0636: { text: "Ordena este cuarto por quién podría romperte el corazón. Luego defiende a quien pusiste primero.", enHash: 3196062269 },
    GRP0637: { text: "Mira a {target}. Ahora di la cosa más vulnerable que de verdad sientes — no lo que desearías sentir, lo que sientes. En voz alta. Ahora.", enHash: 521741778 },
    GRP0638: { text: "Cargas algo suave y tierno que aprendiste a mantener fuera de vista. ¿Qué inseguridad escondes tan bien que nadie aquí la ha adivinado?", enHash: 3207226398 },
    GRP0639: { text: "Piensa en la última vez que alguien te hizo sentir genuina, completamente visto. ¿Cuándo fue — y qué exactamente hicieron?", enHash: 2923980673 },
    GRP0641: { text: "La palabra 'o sea' muere en tus labios hasta tu próximo turno. Cada vez que casi se escapa, trágatela. Quiero escuchar quién eres de verdad cuando no puedes esconderte tras el relleno.", enHash: 2388189093 },
    GRP0642: { text: "Un momento. Una decisión en el amor que desearías poder alcanzar y deshacer. Nómbrala. Ya sé cuál es la que más pesa.", enHash: 2871620774 },
    GRP0643: { text: "Mira a {target}. Dile al cuarto cómo crees que necesita ser amado — palabras, contacto, tiempo, pruebas. Luego pregúntale a {target} qué tan equivocado estás.", enHash: 95410118 },
    GRP0644: { text: "Antes de que termine esta noche, cuela una mentira en tus respuestas. No la anuncies. Deja que se pregunten cuál verdad era un fantasma.", enHash: 2298676389 },
    GRP0645: { text: "Abre tus mensajes. Encuentra el intercambio de DM que te hace esa cara. Léelo en voz alta. El cuarto puede hacer una pregunta de seguimiento — y no serán gentiles.", enHash: 1193167034 },
    GRP0646: { text: "Dile a {target} qué pensaste de verdad el primer momento en que lo viste. Luego dile qué lo reemplazó. Ambas partes. Sin suavizar.", enHash: 1482031311 },
    GRP0647: { text: "De pie. La cabeza atrás. Abre la garganta y aúlla — fuerte, crudo, sin disculpas. Deja que este cuarto escuche cómo suenas cuando dejas de actuar.", enHash: 3154201712 },
    GRP0649: { text: "Cierra los ojos. Mantenlos cerrados. {target} va a darte de comer algo de la mesa, y no sabrás qué es hasta que toque tus labios.", enHash: 2450696481 },
    GRP0650: { text: "Entrega tu teléfono y abre tu tiempo de pantalla. Lee el número en voz alta. Cada hora. Deja que veamos en qué te gastas de verdad.", enHash: 2629912465 },
    GRP0651: { text: "Agarra esa cebolla cruda. Muérdela como si nada. Mastícala despacio. Deja que veamos tu cara decidir si sentir vergüenza.", enHash: 633730919 },
    GRP0652: { text: "Ahora eres {target}. Sus gestos, su voz, su forma de moverse. Quédate en su piel hasta que vuelva tu turno. Que sea convincente.", enHash: 4107633698 },
    GRP0653: { text: "La primera palabra que suba a tu mente ahora mismo — dila en voz alta antes de pensar en lo que revela. Ahora.", enHash: 3028962791 },
    GRP0654: { text: "Ojos cerrados. Mantenlos así hasta tu próximo turno. Escucharás todo pero no verás nada. Deja que el cuarto exista sin tu vigilancia.", enHash: 3212640697 },
    GRP0655: { text: "Cinco minutos. Ni una sola risa — ni el aliento de una. Estaré mirando tu cara. El cuarto tiene permiso de provocarte.", enHash: 2825341345 },
    GRP0656: { text: "Un litro entero de leche. Sírvelo. Bébete cada gota mientras miramos. Esto no es una negociación.", enHash: 2347239617 },
    GRP0657: { text: "Ponte de pie. Tienes treinta segundos para dar tu discurso de aceptación del Oscar — por tu vida amorosa. Agradece a todos. No lo digas en serio con ninguno. O dilo en serio con todos.", enHash: 533320837 },
    GRP0658: { text: "Cada persona en este cuarto recibe un apodo de tu parte. Solo por esta noche. Haz que cada uno aterrice en algo cierto.", enHash: 2233761574 },
    GRP0660: { text: "La cosa que has estado callando toda la noche. Dila. En voz alta. Al cuarto. Ahora mismo.", enHash: 156397367 },
    GRP0661: { text: "Un minuto. Escribe un poema. No me importa si es malo — me importa si es tuyo. Léelo cuando se acabe el tiempo.", enHash: 4047287159 },
    GRP0662: { text: "Tres nombres. Las últimas tres personas que ocuparon tu mente con las luces apagadas y todo en silencio. Dilos en voz alta. Sin ediciones.", enHash: 312439192 },
    GRP0663: { text: "Una cucharadita llena de salsa picante. Echa la cabeza atrás. Tómala limpia. Deja que tu cuerpo reaccione como necesite.", enHash: 1224600559 },
    GRP0664: { text: "Vacía tu bolsa en el piso frente a nosotros. Todo. Cada recibo, cada secreto, cada cosa que creíste que nadie vería.", enHash: 1998575048 },
    GRP0665: { text: "Ponte de pie. 'A Mi Manera'. A todo volumen, de principio a fin — o hasta que quedemos satisfechos. Sinatra tenía la voz. Tú tienes otra cosa. Úsala.", enHash: 3604250891 },
    GRP0666: { text: "Desde este momento hasta tu próximo turno, tu boca solo habla en inglés fingido. Ni una palabra de otra forma, querido. Notaremos cada desliz.", enHash: 232635456 },
    GRP0667: { text: "Dos calcetines. Uno en cada mano. Ponles nombre a tus títeres y actúa. El cuarto es tu público. Haz que sientan algo.", enHash: 2939529503 },
    GRP0668: { text: "Camina a la regadera y métete — completamente vestido, tal como estás. Ábrela. Quédate ahí. Vuelve cuando termines.", enHash: 1889829060 },
    GRP0669: { text: "Mira a cada persona de este cuarto a los ojos, una por una. Dale a cada uno el consejo que de verdad necesita escuchar. No el amable. El real.", enHash: 3629791493 },
    GRP0670: { text: "Elige una canción. Cántale el coro a {target} — no hacia {target}, a {target}. Los ojos fijos todo el tiempo. Ni se te ocurra apartar la mirada.", enHash: 1829001572 },
    GRP0672: { text: "Todo lo que hagas durante los próximos tres minutos pasa en cámara lenta. Cada gesto, cada movimiento, cada respiración. Muévete como si el tiempo fuera algo tuyo.", enHash: 22520128 },
    GRP0673: { text: "Sin música. Sin excusas. Macarena completa — cada paso, en orden, de memoria. El cuarto está mirando y ya están sonriendo.", enHash: 1774759191 },
    GRP0674: { text: "El grupo elige un producto — cualquier producto en este cuarto. Tienes sesenta segundos para venderlo como si tu vida dependiera de ello. La cámara está grabando. Ve.", enHash: 2593460466 },
    GRP0675: { text: "Un diente de ajo crudo entero. Ponlo en tu boca. Mastícalo despacio. Trágalo y siéntelo asentarse. Tú elegiste esto.", enHash: 3418570895 },
    GRP0676: { text: "Tu pelo le pertenece a {target} ahora. Quédate quieto. Deja que trabaje. La forma que te dé, la llevas hasta tu próximo turno — sin espejos, sin quejas.", enHash: 3705125393 },
    GRP0677: { text: "Un minuto en el reloj. Rap freestyle — y cada persona de este cuarto tiene su propio verso. No te saltes a nadie. No seas amable a menos que lo digas en serio.", enHash: 865851785 },
    GRP0678: { text: "Escarba hasta el fondo de tu bolsa y saca la cosa más extraña que vive ahí. Levántala. Ahora explícala.", enHash: 1171210347 },
    GRP0679: { text: "El escenario es tuyo. Cinco minutos de stand-up. Este cuarto es tu público y ya te están juzgando. Haz que lo olviden.", enHash: 1499498446 },
    GRP0680: { text: "Sírvete un shot de lo que esté más cerca y más peligroso. Bébelo limpio. No hagas gesto. O hazlo. Pero termínalo.", enHash: 3523127077 },
    GRP0681: { text: "No estás bebiendo solo. Acerca a {target} y sírvele un shot. Beban juntos, en el mismo momento. Los ojos abiertos.", enHash: 2913769111 },
    GRP0682: { text: "Tu chiste más sucio. Ese que solo cuentas cuando crees que el cuarto lo aguanta. Cuéntalo ahora. Nosotros decidimos si podemos.", enHash: 1925004206 },
    GRP0683: { text: "Mira alrededor de este cuarto. Una de estas personas es tu mejor amigo esta noche. Nómbrala en voz alta. Todos los demás lo escucharán.", enHash: 4229613465 },
    GRP0685: { text: "Encuentra a un desconocido — alguien fuera de este cuarto — y pídele que te califique del uno al diez. Vuelve y reporta el número. Exactamente como te lo dio.", enHash: 2647172381 },
    GRP0686: { text: "Entrega tu pelo a {target}. Quédate quieto y deja que haga lo que quiera con él. Llevas su creación por tres turnos completos. Sin espiar hasta que termine.", enHash: 2846060197 },
    GRP0687: { text: "El cuarto acaba de inventarte un talento — algo absurdo, algo que nunca has hecho. Interprétalo por treinta segundos como si lo hubieras hecho toda tu vida.", enHash: 800571967 },
    GRP0688: { text: "La cosa más escandalosa que has hecho en la vida. No una versión de ella — la cosa misma. Dila en voz alta. El cuarto está escuchando y yo ya lo sé.", enHash: 506641531 },
    GRP0689: { text: "Hay una foto tuya que te hunde el estómago cada vez que recuerdas que existe. Descríbela por completo — dónde estabas, qué hacías, qué hacía tu cara. No te saltes la peor parte.", enHash: 2648467708 },
    GRP0690: { text: "Tres búsquedas. Las que escribiste cuando nadie miraba y creíste que la pantalla era el único testigo. Léelas en voz alta. Despacio.", enHash: 1236365811 },
    GRP0691: { text: "Da la vuelta al cuarto. Cada persona recibe un insulto de tu parte — específico, observado y cierto. Sin suavizar. Sin 'era broma'. Entrega cada uno y sostén su mirada.", enHash: 809586403 },
    GRP0692: { text: "Serenata a {target}. Encuentra una melodía, encuentra las palabras, y deja que cada nota cargue el peso de algo que de verdad sientes. Lyra está escuchando lo que no dices.", enHash: 75724554 },
    GRP0693: { text: "Elige una escena de una novela romántica — el momento cargado, el casi beso, la entrega. Actúala solo o jala a alguien. Haz que el cuarto lo sienta.", enHash: 3441791933 },
    GRP0694: { text: "{actor}, nunca antes has conocido a {target}. Este es el primer segundo. Tus ojos encuentran los suyos al otro lado de un cuarto lleno de gente. Empieza. Lyra te dirá cuándo arranca el tiempo.", enHash: 58088805 },
    GRP0695: { text: "Hasta tu próximo turno, solo salen de tus labios palabras de cuatro letras o menos. Lyra encuentra fascinante cuánto puedes decir aún cuando te obligan a ser pequeño.", enHash: 3386263695 },
    GRP0696: { text: "Elige una escena. Métete en ella por completo — la postura, la voz, el momento. Dales apenas lo suficiente para reconocerla, y deja que vengan a ti.", enHash: 2546300024 },
    GRP0697: { text: "De pie. Llena los pulmones. Ahora grita tu verdad más vergonzosa a todo volumen para que las paredes la recuerden incluso después de que desees que no.", enHash: 983709076 },
    GRP0700: { text: "Alguien trae hielo. Lo presiona contra tu piel desnuda — donde elija. Te quedas quieto. Lo sostienes ahí hasta que no puedas. Lyra está contando los segundos.", enHash: 2658069881 },
    GRP0701: { text: "Treinta segundos como tu jefe. La postura, la cadencia, las pequeñas jugadas de poder que creen que nadie nota. Danos cada detalle vergonzoso. Haz que los reconozcamos.", enHash: 3285891826 },
    GRP0702: { text: "Abre tu teléfono. Encuentra el GIF más demente de tu galería y mándaselo a un compañero de trabajo ahora mismo. Sin texto. Sin contexto. Sin piedad. Muéstranos cuando esté hecho.", enHash: 1571528954 },
    GRP0703: { text: "Tienes dos minutos y toda la autoridad. Ponte de pie. Da el discurso motivacional que de verdad prendería a alguien. Lyra espera que creas cada palabra.", enHash: 2720687261 },
    GRP0704: { text: "Cuéntanos de tu peor día en el trabajo. Cada pequeña humillación, cada momento en que aguantaste cuando no debías. Que duela. Haz que nos riamos a pesar de todo.", enHash: 3883829916 },
    GRP0706: { text: "Elige una palabra. Una palabra con calor adentro. Dila despacio, como si no tuvieras a dónde más ir. Déjala colgando en el aire. Mira hacia dónde van los ojos de todos.", enHash: 1395729699 },
    GRP0707: { text: "Cántale a {target} una canción de amor — no actuando, no en broma. Cada palabra apuntada directo a {target} como si tú la hubieras escrito. No apartes la mirada.", enHash: 3000790976 },
    GRP0709: { text: "Cuenta un chiste sucio usando solo palabras limpias. Sin groserías, sin eufemismos — solo insinuación tan precisa que colorea cada cara del cuarto de todas formas.", enHash: 151127016 },
    GRP0711: { text: "Enrosca tu pelo una vez. Muerde tu labio inferior. Deja escapar un solo suspiro y susurra la palabra — 'Ups'. La entrega lo es todo. Lyra está calificando esto.", enHash: 2297556982 },
    GRP0712: { text: "Baja al piso. Acomódate. Extiende cada extremidad como si la cámara llevara treinta segundos grabando y ya supieras exactamente cómo se ve esto.", enHash: 2506356621 },
    GRP0713: { text: "Fija la mirada en {target}. No apartes la vista. Respira. Luego murmúralo — 'Me vuelves loco' — bajo, lo suficiente para que tenga que inclinarse para estar seguro de que lo oyó.", enHash: 65625153 },
    GRP0714: { text: "Abre tu teléfono. Léele a {target} tus últimas tres búsquedas. En voz alta. En orden. Sin saltarte ninguna, sin suavizar, sin explicación a menos que pregunte.", enHash: 95825094 },
    GRP0716: { text: "Reduce a tu ex más significativo a un solo emoji. Sin palabras — actúalo hasta que todos aquí adivinen exactamente a quién te refieres. Lyra ya lo sabe.", enHash: 472021639 },
    GRP0717: { text: "Abre el último mensaje que le enviaste a {target}. Léelo completo en voz alta. Si era nada, léelo como si fuera todo. Si era todo, no apartes la mirada de {target}.", enHash: 236945417 },
    GRP0719: { text: "Cuéntanos la cosa más graciosa que te pasó esta semana. No la versión que editaste para el grupo — la versión que te contaste a las dos de la mañana.", enHash: 556679929 },
    GRP0721: { text: "Sostén la mirada de {target} y suelta tu línea más suave. Despacio. Como si la hubieras estado guardando. Lyra te prohíbe sonreír hasta que {target} lo haga.", enHash: 2687812170 },
    GRP0723: { text: "Estás perdida, vergonzosamente enamorado. Dos minutos. Danos el desmayo — la mirada de anhelo, la mano en el pecho, cada insoportable gesto romántico. Dilo en serio.", enHash: 674062449 },
    GRP0724: { text: "Dile algo romántico a {target}. No gracioso, no irónico — cierto. Algo que aterrice en el pecho. Lyra sabrá si estás fingiendo.", enHash: 551775376 },
    GRP0725: { text: "Te han captado en cámara haciendo algo que desearías que el mundo nunca hubiera visto. Reactúalo. Cada detalle. Lyra quiere la versión completa, no la que cuentas en las fiestas.", enHash: 3946982268 },
    GRP0726: { text: "Describe la peor foto tuya que existe. La luz, el ángulo, qué llevabas puesto, qué hacía tu cara. Píntala tan preciso que podamos verla sin mirar.", enHash: 1881630217 },
    GRP0727: { text: "Improvisa un rap sobre {target}. Sus hábitos, su energía, su marca particular de caos. Haz que aterrice. Lyra no tiene paciencia para murmullos.", enHash: 3868977782 },
    GRP0728: { text: "Mira a cada jugador por turno — míralo de verdad — y dale el único consejo que de verdad necesita ahora mismo. Que sea específico. Que sea cierto.", enHash: 1336951254 },
    GRP0729: { text: "Gira quince veces, rápido. Luego camina una línea recta a través del cuarto sin tocar pared ni cuerpo. Lyra encuentra muy revelador lo que la gravedad muestra de una persona.", enHash: 4000722930 },
    GRP0730: { text: "Nombra la cosa que más te asusta cuando el cuarto está vacío y nadie mira. No el miedo que actúas — el que se sienta callado detrás de tus costillas.", enHash: 438718431 },
    GRP0731: { text: "Hay algo que tus padres se llevarán a la tumba sin saber jamás de ti. Lyra lo sabe. Dilo en voz alta y deja que el cuarto lo sostenga por ellos.", enHash: 2398245153 },
    GRP0732: { text: "Hay alguien en tu vida a quien estuviste peligrosamente cerca de desear — alguien a quien no tenías por qué desear. Lyra puede ver el nombre formándose. Di qué tan cerca llegaste.", enHash: 3633666936 },
    GRP0733: { text: "Suelta un secreto que le pertenece a alguien más. Deja el nombre enterrado, pero danos lo suficiente para que respire. Lyra aprecia un secreto contado con precisión.", enHash: 3993847344 },
    GRP0734: { text: "Hay un secreto romántico sellado dentro de ti que nadie vivo ha escuchado. Lyra está abriendo el sello ahora. Dale una voz.", enHash: 4146534700 },
    GRP1185: { text: "Ambos vecinos tienen turno. Te quedas perfectamente quieto mientras cada uno te planta un lengüetazo mojado directo en la oreja. Ese es el reto.", enHash: 3655370903 },
    GRP1407: { text: "Alguien hizo algo ilegal — o algo sucio — y tú lo sabías. ¿Lo reportaste, lo enterraste, o lo usaste? Dime exactamente qué hicieron y qué elegiste hacer con la información.", enHash: 2764374863 },
    HMR001: { text: "Ponte de pie y danos tu mejor imitación de cómo te ves cuando suena la alarma un lunes.", enHash: 607444784 },
    HMR002: { text: "¿Cuál es la canción más vergonzosa de la que te sabes cada palabra? Demuéstralo — canta el coro.", enHash: 1464961476 },
    HMR003: { text: "Haz tu mejor caminado sexy a través del cuarto. Comprométete. Sin medias tintas.", enHash: 2715443398 },
    HMR004: { text: "Si tu vida amorosa fuera una película, ¿cuál sería el título? Los demás pueden sugerir uno mejor.", enHash: 3202166726 },
    HMR005: { text: "{actor}, mira a {target} fijamente a los ojos y dale la confesión de amor más dramática de telenovela que puedas lograr. En cualquier acento.", enHash: 2411704646 },
    HMR006: { text: "Cuéntanos de tu peor cita — pero tienes que actuar el comportamiento de la otra persona.", enHash: 3425967676 },
    HMR007: { text: "¿Cuál es la cosa más ridícula que has hecho para impresionar a alguien que te gustaba? ¿Funcionó?", enHash: 2857111082 },
    HMR008: { text: "Todos votan: ¿quién aquí sobreviviría más tiempo en una isla desierta? El ganador tiene que explicar su estrategia en 15 segundos.", enHash: 3242122423 },
    HMR009: { text: "¿Cuál es la mentira más grande que has dicho en una cita? El grupo decide si fue suave o desesperada.", enHash: 1896163292 },
    HMR010: { text: "{actor}, finge que {target} acaba de proponerte matrimonio. Danos la reacción — lágrimas, gritos, desmayo, lo que de verdad harías.", enHash: 3891357738 },
    MINI_06: { text: "¡Todos escriban quién creen que tiene el secreto más interesante de este cuarto. ¡Lo revelan en tres!", enHash: 3067177276 },
    MINI_07: { text: "¡Silla caliente! {player} se sienta en el centro. Todos le hacen una pregunta personal. Hay que responderlas todas.", enHash: 3969438712 },
    MINI_09: { text: "Todos responden: ¿qué es lo que siempre quisiste saber de alguien en este cuarto pero nunca te animaste a preguntar? Dilo ahora.", enHash: 2616843666 },
    MINI_11: { text: "¡Todos cierren los ojos. Apunten a quien creen que lloraría más rápido viendo una película. ¡Abran los ojos!", enHash: 1614837827 },
    PRF_B01: { text: "¿Qué es algo que has hecho y que solo admitirías a un amigo cercano?", enHash: 1577728993 },
    PRF_B02: { text: "¿Alguna vez has hecho algo vergonzoso a propósito — solo para ver cómo reacciona la gente?", enHash: 398550779 },
    PRF_B03: { text: "¿Cuál es la 'regla' social más grande que en secreto te da igual?", enHash: 1816261331 },
    PRF_B04: { text: "Si nadie que conoces pudiera reconocerte por una noche, ¿qué es lo primero que harías?", enHash: 3918459800 },
    PRF_B05: { text: "¿Cuál es un lado tuyo que solo sale cuando has tomado unas copas?", enHash: 2568210360 },
    PRF_C01: { text: "¿Juegas para ganar o para divertirte — y sé honesto.", enHash: 962604883 },
    PRF_C02: { text: "¿Alguna vez has dejado ganar a alguien? ¿Se sintió bien o te molestó?", enHash: 2477396997 },
    PRF_C03: { text: "Si el grupo votara por saltarse un reto esta noche, ¿estarías aliviado o decepcionado?", enHash: 3456154439 },
    PRF_C04: { text: "¿A quién en este cuarto crees que sería más difícil ganarle en su propio juego?", enHash: 3626347944 },
    PRF_C05: { text: "¿Cuál es la cosa más mezquina que has hecho para ganar una discusión?", enHash: 1850707865 },
    PRF_D01: { text: "¿Cuál es una cosa que te haría rendirte al instante de un reto esta noche?", enHash: 1490928375 },
    PRF_D02: { text: "¿Hay algo que harías frente a desconocidos que no harías frente a gente que conoces?", enHash: 183289486 },
    PRF_D03: { text: "Ordena estas de más fácil a más difícil para ti: reto físico, honestidad emocional, o ridiculez pública.", enHash: 3861406534 },
    PRF_D04: { text: "¿Cuál es el punto más fuera de tu zona de confort al que has llegado voluntariamente — y lo volverías a hacer?", enHash: 344659806 },
    PRF_D05: { text: "Mira a {target}. ¿Cuál crees que es su límite esta noche — y estás dispuesto a probarlo?", enHash: 1466923875 },
    PRF_E01: { text: "¿Cuál es un cumplido que recibes seguido y con el que en secreto estás de acuerdo?", enHash: 4104240608 },
    PRF_E02: { text: "¿Qué suele malinterpretar la gente de ti cuando te conoce por primera vez?", enHash: 706992288 },
    PRF_E03: { text: "¿Cuál es tu mayor orgullo — algo de lo que estás genuinamente orgulloso pero rara vez dices en voz alta?", enHash: 1049733108 },
    PRF_E04: { text: "Describe a {target} en tres palabras — y haz que al menos una sea incómodamente acertada.", enHash: 1101288022 },
    PRF_E05: { text: "¿Cuál rasgo de tu personalidad crees que todos aquí van a notar antes de que termine la noche?", enHash: 3886599884 },
    PRF_J01: { text: "Sin rodeos — ¿eres de los que se ponen celosos? El orbe quiere saberlo.", enHash: 3600550908 },
    PRF_J02: { text: "Si alguien le tirara el perro a tu pareja justo frente a tus narices — ¿qué harías de verdad?", enHash: 2523507372 },
    PRF_J05: { text: "En una escala del 1 al 5, ¿qué tan celoso eres? ¿Y tu pareja estaría de acuerdo con ese número?", enHash: 2015822412 },
    PRF_O01: { text: "¿Cuál es un tema del que no sabes casi nada pero que encuentras genuinamente fascinante?", enHash: 1508610291 },
    PRF_O02: { text: "Si pudieras hacerle a {target} una pregunta que tuviera que responder con honestidad — ¿cuál sería?", enHash: 1864209448 },
    PRF_O03: { text: "¿Qué es algo sobre lo que recientemente cambiaste de opinión?", enHash: 1930472351 },
    PRF_O04: { text: "¿Cuál es un tema de conversación que siempre atrapará tu atención — sin importar quién hable?", enHash: 1917572216 },
    PRF_O05: { text: "¿Alguna vez te has equivocado por completo con alguien después de tu primera impresión? ¿Qué cambió?", enHash: 3312779452 },
    PRF_R01: { text: "¿Cuál es la cosa más espontánea que has hecho — y valió la pena?", enHash: 4101372192 },
    PRF_R02: { text: "Si tuvieras que apostar a que harás algo atrevido esta noche, ¿qué sería?", enHash: 4025008241 },
    PRF_R03: { text: "¿Preferirías saber exactamente qué viene después — o no tener ni idea?", enHash: 2430548830 },
    PRF_R04: { text: "¿Alguna vez has dicho que sí a algo antes de que tu cerebro tuviera tiempo de decir que no?", enHash: 2676665233 },
    PRF_R05: { text: "Mira a {target}. ¿Sería del tipo que lleva un reto demasiado lejos — o no lo suficiente?", enHash: 2095270655 }
  },

  // Engine/UI strings: key -> Spanish text.
  // {name}/{judge} placeholders are substituted by the engine.
  ui: {
    // Vote & verdict overlays
    "vote.dare": "¿Qué tal lo hizo {name}? {judge} puntúa del 1 al 5.",
    "vote.truth": "¿{name} reveló lo suficiente? {judge} decide.",
    "verdict.question": "El momento de la verdad: ¿{name} acertó? {judge} decide.",
    "verdict.correct": "CORRECTO",
    "verdict.wrong": "FALLASTE — ¡BEBE!",
    "verdict.cheers": "¡SALUD!",

    // Feedback buttons
    "btn.done": "HECHO",
    "btn.answered": "RESPONDIDO",
    "btn.refused": "RECHAZADO",
    "btn.pass": "PASO",
    "btn.spin": "GIRA ({n})",

    // Judges
    "judge.partner": "Tu pareja",
    "judge.group": "El grupo"
  }
};
